val workRequest = OneTimeWorkRequestBuilder<LogUploadWorker>().build()
WorkManager.getInstance(context).enqueue(workRequest)

class LogUploadWorker(context: Context, params: WorkerParameters) :
    CoroutineWorker(context, params) {
    override suspend fun doWork(): Result {
        uploadLogsToServer()  // a suspend function
        return Result.success()
    }
}

// One-time: runs exactly once
val oneTime = OneTimeWorkRequestBuilder<LogUploadWorker>().build()

// Periodic: runs repeatedly, roughly every 6 hours
val periodic = PeriodicWorkRequestBuilder<LogUploadWorker>(6, TimeUnit.HOURS).build()

// User taps "Enable Auto-Sync" multiple times by accident
WorkManager.getInstance(context).enqueueUniquePeriodicWork(
    "log_sync",
    ExistingPeriodicWorkPolicy.KEEP,
    periodicWorkRequest
)
